import React, { useState, useMemo, useCallback, useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import {
  dispatchAppToast,
  erpReportTableConfigFromDisplay,
  LIN_ERP_LIST_FILTER_LAYOUT,
  LinPageLayout,
  LinReportPrintScopeModal,
  LinReportTableConfigModal,
  fetchReportPagesInBatches,
  loadErpReportDisplayConfig,
  resolveReportCharts,
  saveErpReportDisplayConfig,
  useServerPagedListLoading,
  ListGridBusyWrap,
  type ErpReportDisplayConfig,
  type ReportPrintScope,
  useViewMobileLayout,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import type { LedgerEntryDto, ReportChartOptionDto } from '../../../services/kt/models';
import { createAccountSearchConfig, useAccountSearchAsOfDate } from '../../../components/search';
import { reportPageLabels } from '../../../constants/reportPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import {
  patchReportFilterFieldError,
  scrollToFirstReportFilterField,
  validateRequiredTrimmed,
  type ReportFilterFieldRef,
} from '../../../utils/reportFilterValidation';
import erp from '../../../styles/erpPage.module.css';
import {
  LedgerReportChartModal,
  LedgerReportGrid,
  ReportPrintSummary,
  normalizeLedgerReportResponse,
} from '../../../components/report';
import type { LedgerChartData } from '../../../components/report/buildLedgerChartData';
import {
  buildSoCaiPrintFilterLines,
  type SoCaiAppliedFilters,
} from '../../../utils/reportPrintFilters';
import type { ReportPrintFilterLine } from '../../../components/report/ReportPrintSummary';
import { triggerErpReportPrint } from '../../../utils/triggerErpReportPrint';
import { runErpReportPrintAfterPaint } from '../../../utils/runErpReportPrintAfterPaint';
import {
  getSoCaiPageSession,
  reportPageSessionKey,
  saveSoCaiPageSession,
} from '../../../components/report/reportPageSessionCache';
import {
  getReportGridRowMenuHintMessage,
  reportGridRowHintDismissStorageKey,
} from '../../../utils/reportGridRowMenuHint';
import { useReportAccountFilterDefault } from '../../../hooks/useReportAccountFilterDefault';
import { buildReportChartQueryParams } from '../../../utils/buildReportChartQueryParams';
import { isReportChartConfigChanged, isReportChartsEnabled } from '../../../utils/erpReportChartPrefs';
import {
  DEFAULT_PAGE_SIZE,
  VoucherListPagination,
} from '../../../components/list/VoucherListPagination';
import { SoCaiReportFilterBar } from './SoCaiReportFilterBar';

const labels = reportPageLabels.soCai;
const TEST_ID = 'erp-so-cai';
const PAGE_ID = 'kt-so-cai';

type SoCaiFilterErrors = {
  accountCode?: string;
};

const SO_CAI_FILTER_FIELDS: readonly ReportFilterFieldRef[] = [
  { errorKey: 'accountCode', fieldSuffix: 'account' },
];

function formatPrintScopeTemplate(template: string, vars: Record<string, string | number>): string {
  return template.replace(/\{(\w+)\}/g, (_, key: string) => String(vars[key] ?? ''));
}

const SoCaiPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const location = useLocation();
  const viewMobile = useViewMobileLayout();
  const rowMenuHintMessage = viewMobile ? labels.rowMenuHintTouch : labels.rowMenuHint;
  const sessionKey = reportPageSessionKey(location.pathname, location.search);
  const cached = getSoCaiPageSession(sessionKey);

  const [accountCode, setAccountCode] = useState(cached?.accountCode ?? '');
  const [accountName, setAccountName] = useState(cached?.accountName ?? '');
  useReportAccountFilterDefault('kt-so-cai-report', cached?.accountCode, accountCode, setAccountCode, setAccountName);
  const [fromDate, setFromDate] = useState<string | undefined>(cached?.fromDate);
  const [toDate, setToDate] = useState<string | undefined>(cached?.toDate);
  const [items, setItems] = useState<LedgerEntryDto[]>(cached?.items ?? []);
  const [page, setPage] = useState(cached?.page ?? 1);
  const [totalCount, setTotalCount] = useState(cached?.totalCount ?? cached?.items?.length ?? 0);
  const [pageSize, setPageSize] = useState<number>(cached?.pageSize ?? DEFAULT_PAGE_SIZE);
  const [allowedCharts, setAllowedCharts] = useState<ReportChartOptionDto[]>([]);
  const [reportChartData, setReportChartData] = useState<LedgerChartData | null>(null);
  const [appliedFilters, setAppliedFilters] = useState<SoCaiAppliedFilters | null>(() => {
    if ((cached?.items?.length ?? 0) === 0) return null;
    return {
      accountCode: cached?.accountCode ?? '111',
      accountName: cached?.accountName,
      fromDate: cached?.fromDate,
      toDate: cached?.toDate,
    };
  });
  const {
    filterLoading,
    pageLoading,
    showTableLoading,
    setLoadingMode,
    beginFetch,
    endFetch,
  } = useServerPagedListLoading();
  const [filterErrors, setFilterErrors] = useState<SoCaiFilterErrors>({});
  const [configOpen, setConfigOpen] = useState(false);
  const [chartOpen, setChartOpen] = useState(false);
  const [printModalOpen, setPrintModalOpen] = useState(false);
  const [printLoading, setPrintLoading] = useState(false);
  const [printItemsOverride, setPrintItemsOverride] = useState<LedgerEntryDto[] | null>(null);
  const [printScopeLine, setPrintScopeLine] = useState<ReportPrintFilterLine | null>(null);
  const [displayConfig, setDisplayConfig] = useState<ErpReportDisplayConfig>(() =>
    loadErpReportDisplayConfig(TEST_ID),
  );
  const tableConfig = useMemo(
    () => erpReportTableConfigFromDisplay(displayConfig),
    [displayConfig],
  );
  const accountSearchOptions = useAccountSearchAsOfDate(fromDate, 'all');
  const accountSearchConfig = useMemo(
    () => createAccountSearchConfig({ ...accountSearchOptions, showLookupWarning: false }),
    [accountSearchOptions],
  );

  useEffect(() => {
    saveSoCaiPageSession(sessionKey, {
      accountCode,
      accountName,
      fromDate,
      toDate,
      items,
      totalCount,
      page,
      pageSize,
    });
  }, [sessionKey, accountCode, accountName, fromDate, toDate, items, totalCount, page, pageSize]);

  const validateFilters = useCallback((): SoCaiFilterErrors => {
    const errors: SoCaiFilterErrors = {};
    const accountError = validateRequiredTrimmed(accountCode, labels.accountRequired);
    if (accountError) errors.accountCode = accountError;
    return errors;
  }, [accountCode]);

  const gridPageSize = useMemo(
    () => (displayConfig.showFooterPagination && pageSize > 0 ? pageSize : Math.max(items.length, 1)),
    [displayConfig.showFooterPagination, pageSize, items.length],
  );

  const showAllPagesPrintOption = useMemo(
    () =>
      displayConfig.showFooterPagination
      && pageSize > 0
      && totalCount > items.length,
    [displayConfig.showFooterPagination, pageSize, totalCount, items.length],
  );

  const gridItems = printItemsOverride ?? items;
  const gridSttPage = printItemsOverride ? 1 : page;
  const gridSttPageSize = printItemsOverride
    ? Math.max(printItemsOverride.length, 1)
    : gridPageSize;

  const fetchLedgerPageWithConfig = useCallback(
    (
      targetPage: number,
      filters: { accountCode: string; fromDate?: string; toDate?: string },
      config: ErpReportDisplayConfig,
      chartCatalog: ReportChartOptionDto[],
      loadingMode: 'filter' | 'page' = 'filter',
    ) => {
      const reqPageSize = config.showFooterPagination ? pageSize : 0;
      const chartQuery = buildReportChartQueryParams(config, chartCatalog);
      setLoadingMode(loadingMode === 'page' ? 'page' : 'filter');
      beginFetch();
      return ktService
        .getLedger({
          accountCode: filters.accountCode,
          fromDate: filters.fromDate,
          toDate: filters.toDate,
          page: targetPage,
          pageSize: reqPageSize,
          ...chartQuery,
        })
        .then(raw => {
          const report = normalizeLedgerReportResponse(raw);
          setItems(report.items);
          setAllowedCharts(report.charts);
          setReportChartData(report.chartData);
          setTotalCount(report.totalCount);
          setPage(report.page);
          return report;
        })
        .catch(err => {
          dispatchAppToast(dispatch, { message: getApiErrorMessage(err, labels.loadError), type: 'error' });
          throw err;
        })
        .finally(() => {
          endFetch();
        });
    },
    [dispatch, labels.loadError, pageSize, setLoadingMode, beginFetch, endFetch],
  );

  const fetchLedgerPage = useCallback(
    (
      targetPage: number,
      filters: { accountCode: string; fromDate?: string; toDate?: string },
      loadingMode: 'filter' | 'page' = 'filter',
    ) => fetchLedgerPageWithConfig(targetPage, filters, displayConfig, allowedCharts, loadingMode),
    [fetchLedgerPageWithConfig, displayConfig, allowedCharts],
  );

  const handleLoad = useCallback(() => {
    const errors = validateFilters();
    if (Object.keys(errors).length > 0) {
      setFilterErrors(errors);
      scrollToFirstReportFilterField(TEST_ID, SO_CAI_FILTER_FIELDS, errors);
      dispatchAppToast(dispatch, { message: labels.filterValidationSummary, type: 'warning' });
      return;
    }
    setFilterErrors({});
    setPage(1);
    fetchLedgerPage(1, { accountCode, fromDate, toDate }).then(() => {
      setAppliedFilters({
        accountCode,
        accountName,
        fromDate,
        toDate,
      });
    }).catch(() => undefined);
  }, [
    accountCode,
    accountName,
    fromDate,
    toDate,
    dispatch,
    validateFilters,
    labels.filterValidationSummary,
    fetchLedgerPage,
  ]);

  const handlePageChange = useCallback(
    (nextPage: number) => {
      if (!appliedFilters || pageLoading) return;
      const prevPage = page;
      setPage(nextPage);
      fetchLedgerPage(nextPage, {
        accountCode: appliedFilters.accountCode,
        fromDate: appliedFilters.fromDate,
        toDate: appliedFilters.toDate,
      }, 'page').catch(() => {
        setPage(prevPage);
      });
    },
    [appliedFilters, pageLoading, page, fetchLedgerPage],
  );

  const handlePageSizeChange = useCallback(
    (nextPageSize: number) => {
      setPageSize(nextPageSize);
      setPage(1);
      if (!appliedFilters) return;
      setLoadingMode('filter');
      beginFetch();
      const chartQuery = buildReportChartQueryParams(displayConfig, allowedCharts);
      ktService
        .getLedger({
          accountCode: appliedFilters.accountCode,
          fromDate: appliedFilters.fromDate,
          toDate: appliedFilters.toDate,
          page: 1,
          pageSize: displayConfig.showFooterPagination ? nextPageSize : 0,
          ...chartQuery,
        })
        .then(raw => {
          const report = normalizeLedgerReportResponse(raw);
          setItems(report.items);
          setAllowedCharts(report.charts);
          setReportChartData(report.chartData);
          setTotalCount(report.totalCount);
          setPage(report.page);
        })
        .catch(err =>
          dispatchAppToast(dispatch, { message: getApiErrorMessage(err, labels.loadError), type: 'error' }),
        )
        .finally(() => endFetch());
    },
    [appliedFilters, displayConfig, allowedCharts, dispatch, labels.loadError, setLoadingMode, beginFetch, endFetch],
  );

  const handlePrint = useCallback(() => {
    if (!appliedFilters || totalCount === 0 || showTableLoading || printLoading) return;
    setPrintModalOpen(true);
  }, [appliedFilters, totalCount, showTableLoading, printLoading]);

  const handlePrintScopeConfirm = useCallback(
    async (scope: ReportPrintScope) => {
      if (!appliedFilters || showTableLoading) return;
      setPrintLoading(true);
      try {
        if (scope === 'allPages') {
          const rowsForPrint = await fetchReportPagesInBatches({
            totalCount,
            batchSize: displayConfig.printFetchBatchSize,
            fetchPage: async (targetPage, batchSize) => {
              const raw = await ktService.getLedger({
                accountCode: appliedFilters.accountCode,
                fromDate: appliedFilters.fromDate,
                toDate: appliedFilters.toDate,
                page: targetPage,
                pageSize: batchSize,
                includeChartData: false,
              });
              return normalizeLedgerReportResponse(raw).items;
            },
          });
          const scopeLine = {
            label: labels.printScopeFilterLabel,
            value: formatPrintScopeTemplate(labels.printScopeAllValue, { total: totalCount }),
          };
          runErpReportPrintAfterPaint(
            () => {
              setPrintItemsOverride(rowsForPrint);
              setPrintScopeLine(scopeLine);
            },
            () => {
              setPrintItemsOverride(null);
              setPrintScopeLine(null);
            },
          );
        } else {
          const scopeLine = {
            label: labels.printScopeFilterLabel,
            value: formatPrintScopeTemplate(labels.printScopeCurrentValue, {
              page,
              count: items.length,
            }),
          };
          runErpReportPrintAfterPaint(
            () => {
              setPrintItemsOverride(null);
              setPrintScopeLine(scopeLine);
            },
            () => {
              setPrintItemsOverride(null);
              setPrintScopeLine(null);
            },
          );
        }

        setPrintModalOpen(false);
      } catch (err) {
        setPrintScopeLine(null);
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, labels.printLoadError),
          type: 'error',
        });
      } finally {
        setPrintLoading(false);
      }
    },
    [
      appliedFilters,
      showTableLoading,
      totalCount,
      displayConfig.printFetchBatchSize,
      dispatch,
      labels.printLoadError,
      labels.printScopeFilterLabel,
      labels.printScopeAllValue,
      labels.printScopeCurrentValue,
      page,
      items.length,
    ],
  );

  const visibleCharts = useMemo(() => {
    if (!isReportChartsEnabled(displayConfig.chart)) return [];
    return resolveReportCharts(allowedCharts, displayConfig.chart);
  }, [allowedCharts, displayConfig.chart]);

  const canShowCharts = totalCount > 0 && visibleCharts.length > 0 && reportChartData != null;

  const handleOpenChart = useCallback(() => {
    if (totalCount === 0 || !reportChartData) return;
    if (visibleCharts.length === 0) {
      dispatchAppToast(dispatch, { message: labels.chartNoTypes, type: 'info' });
      return;
    }
    setChartOpen(true);
  }, [totalCount, reportChartData, visibleCharts.length, dispatch, labels.chartNoTypes]);

  const chartLabels = useMemo(
    () => ({
      title: labels.chartTitle,
      kpiTotalDebit: labels.chartKpiTotalDebit,
      kpiTotalCredit: labels.chartKpiTotalCredit,
      kpiClosingBalance: labels.chartKpiClosingBalance,
      kpiClosingBalanceDebit: labels.chartKpiClosingBalanceDebit,
      kpiClosingBalanceCredit: labels.chartKpiClosingBalanceCredit,
      kpiEntryCount: labels.chartKpiEntryCount,
      seriesDebit: labels.chartSeriesDebit,
      seriesCredit: labels.chartSeriesCredit,
      seriesBalanceDebit: labels.chartSeriesBalanceDebit,
      seriesBalanceCredit: labels.chartSeriesBalanceCredit,
      viewFull: labels.chartViewFull,
      empty: labels.chartEmpty,
      noCharts: labels.chartNoTypes,
    }),
    [labels],
  );

  const handleSaveDisplayConfig = (next: ErpReportDisplayConfig) => {
    const paginationChanged = next.showFooterPagination !== displayConfig.showFooterPagination;
    const chartChanged = isReportChartConfigChanged(displayConfig.chart, next.chart);
    setDisplayConfig(next);
    saveErpReportDisplayConfig(TEST_ID, next);
    if ((paginationChanged || chartChanged) && appliedFilters) {
      setPage(1);
      fetchLedgerPageWithConfig(1, {
        accountCode: appliedFilters.accountCode,
        fromDate: appliedFilters.fromDate,
        toDate: appliedFilters.toDate,
      }, next, allowedCharts).catch(() => undefined);
    }
  };

  const hasData = appliedFilters != null && totalCount > 0;
  const canPrint = hasData && !showTableLoading && !printLoading && !pageLoading;

  const reportFilters = useMemo(
    () => (
      <SoCaiReportFilterBar
        testIdPrefix={TEST_ID}
        labels={labels}
        accountSearchConfig={accountSearchConfig}
        accountCode={accountCode}
        accountName={accountName}
        accountError={filterErrors.accountCode}
        onAccountChange={(code, name) => {
          patchReportFilterFieldError(setFilterErrors, 'accountCode');
          setAccountCode(code);
          setAccountName(name);
        }}
        onAccountClear={() => {
          patchReportFilterFieldError(setFilterErrors, 'accountCode');
          setAccountCode('');
          setAccountName('');
        }}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={(from, to) => {
          setFromDate(from);
          setToDate(to);
        }}
        onView={handleLoad}
        loading={filterLoading}
      />
    ),
    [
      accountSearchConfig,
      accountCode,
      accountName,
      filterErrors.accountCode,
      fromDate,
      toDate,
      handleLoad,
      filterLoading,
    ],
  );

  const reportToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: handleLoad,
      canChart: canShowCharts,
      onChart: handleOpenChart,
      canPrint,
      onPrint: handlePrint,
      onEditConfig: () => setConfigOpen(true),
    }),
    [handleLoad, canShowCharts, handleOpenChart, handlePrint, canPrint],
  );

  const printFilterLines = useMemo(() => {
    if (!appliedFilters) return [];
    const base = buildSoCaiPrintFilterLines(appliedFilters, labels);
    return printScopeLine ? [...base, printScopeLine] : base;
  }, [appliedFilters, labels, printScopeLine]);

  const listBody = !showTableLoading && totalCount === 0 ? (
    <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>{labels.empty}</div>
  ) : !showTableLoading ? (
    <>
      {appliedFilters ? (
        <ReportPrintSummary
          title={labels.title}
          filters={printFilterLines}
          testIdPrefix={TEST_ID}
        />
      ) : null}
      <ListGridBusyWrap pageLoading={pageLoading}>
        <LedgerReportGrid
        items={gridItems}
        labels={labels}
        testIdPrefix={TEST_ID}
        page={gridSttPage}
        pageSize={gridSttPageSize}
        exportAccountCode={accountCode}
        reportTitle={labels.title}
        onRefresh={handleLoad}
        onPrint={handlePrint}
        onChart={handleOpenChart}
        canChart={canShowCharts}
        canViewReportDetail
        detailReportTitle={reportPageLabels.soChiTiet.title}
        tableConfig={tableConfig}
        getRowMenuHintMessage={getReportGridRowMenuHintMessage(rowMenuHintMessage)}
        rowMenuHintDismissStorageKey={reportGridRowHintDismissStorageKey(TEST_ID)}
        />
      </ListGridBusyWrap>
    </>
  ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-report-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="report"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={erp.catalogListPage}
        listLayoutVariant="erp-filter-bar"
        listHeaderClassName={LIN_ERP_LIST_FILTER_LAYOUT.header}
        listFiltersClassName={LIN_ERP_LIST_FILTER_LAYOUT.filtersHost}
        header={{
          title: labels.title,
          titleIconClass: 'fas fa-book-open',
          pageId: PAGE_ID,
        }}
        reportToolbar={reportToolbar}
        listTitle={labels.listTitle}
        listRowMenuHelp
        listTitleHelpAsIcon
        filters={reportFilters}
        filterBarLayout="standard"
        showTableLoading={showTableLoading}
        pageLoading={pageLoading}
        skeletonRows={8}
        footer={
          displayConfig.showFooterPagination && totalCount > 0 && pageSize > 0 ? (
            <VoucherListPagination
              testIdPrefix={TEST_ID}
              page={page}
              totalCount={totalCount}
              pageSize={pageSize}
              onPageChange={handlePageChange}
              onPageSizeChange={handlePageSizeChange}
            />
          ) : undefined
        }
        modals={(
          <>
            <LinReportTableConfigModal
              isOpen={configOpen}
              onClose={() => setConfigOpen(false)}
              testIdPrefix={TEST_ID}
              config={displayConfig}
              chartCatalog={allowedCharts}
              onSave={handleSaveDisplayConfig}
              title={labels.configModalTitle}
              sectionGridLabel={labels.configSectionGrid}
              sectionFooterLabel={labels.configSectionFooter}
              sectionPrintLabel={labels.configSectionPrint}
              printBatchSizeLabel={labels.configPrintBatchSizeLabel}
              printBatchSizeHint={labels.configPrintBatchSizeHint}
              sectionChartLabel={labels.configSectionChart}
              chartEmptyHint={labels.configChartEmptyHint}
            />
            <LinReportPrintScopeModal
              isOpen={printModalOpen}
              onClose={() => !printLoading && setPrintModalOpen(false)}
              onConfirm={handlePrintScopeConfirm}
              printing={printLoading}
              testIdPrefix={TEST_ID}
              currentPage={page}
              currentPageRowCount={items.length}
              totalCount={totalCount}
              showAllPagesOption={showAllPagesPrintOption}
              labels={{
                title: labels.printModalTitle,
                scopeLabel: labels.printScopeLabel,
                currentPageOption: labels.printCurrentPageOption,
                allPagesOption: labels.printAllPagesOption,
                cancel: labels.printCancel,
                confirm: labels.printConfirm,
                fetchHint: labels.printFetchHint,
              }}
            />
            <LedgerReportChartModal
              isOpen={chartOpen}
              onClose={() => setChartOpen(false)}
              items={items}
              allowedCharts={visibleCharts}
              chartData={reportChartData ?? undefined}
              showKpiStrip={displayConfig.chart.showKpiStrip}
              filterLines={printFilterLines}
              labels={chartLabels}
              testIdPrefix={TEST_ID}
            />
          </>
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default SoCaiPage;
